const { test, expect } = require('@playwright/test');

test('Header navigation validation', async ({ page }) => {
  await page.setViewportSize({ width: 375, height: 812 });
  await page.goto('http://localhost:3002');

  // Verify Home (Brand)
  const brand = page.getByRole('link', { name: 'okwasniewski' });
  await expect(brand).toBeVisible();
  await brand.click();
  await expect(page).toHaveURL('http://localhost:3002/');

  // Verify Blog
  const blog = page.getByRole('link', { name: 'blog' });
  await expect(blog).toBeVisible();
  await blog.click();
  await expect(page).toHaveURL('http://localhost:3002/blog');

  // Verify Portfolio
  const portfolio = page.getByRole('link', { name: 'portfolio' });
  await expect(portfolio).toBeVisible();
  await portfolio.click();
  await expect(page).toHaveURL('http://localhost:3002/portfolio');

  // Verify Videos
  const videos = page.getByRole('link', { name: 'videos' });
  await expect(videos).toBeVisible();
  await videos.click();
  await expect(page).toHaveURL('http://localhost:3002/videos');

  // Verify Contact (This is where the bug is)
  const contact = page.getByRole('link', { name: 'contact' });
  await expect(contact).toBeVisible();
  await contact.click();
  // Expecting /contact but found /contcat which results in 404
  await expect(page).toHaveURL('http://localhost:3002/contact');
});
